import React, { useEffect } from 'react';

const FacebookReviews = () => {
  useEffect(() => {
    // Load Facebook SDK
    if (!document.getElementById('facebook-jssdk')) {
      const script = document.createElement('script');
      script.id = 'facebook-jssdk';
      script.src = 'https://connect.facebook.net/bg_BG/sdk.js#xfbml=1&version=v18.0';
      script.async = true;
      script.defer = true;
      script.crossOrigin = 'anonymous';
      document.body.appendChild(script);
    }
  }, []);

  const styles = {
    section: {
      padding: '120px 24px',
      backgroundColor: '#18181b',
    },
    container: {
      maxWidth: '800px',
      margin: '0 auto',
      textAlign: 'center',
    },
    tagline: {
      fontSize: '12px',
      textTransform: 'uppercase',
      letterSpacing: '4px',
      color: '#e2bc6f',
      marginBottom: '16px',
    },
    title: {
      fontFamily: 'Playfair Display, serif',
      fontSize: 'clamp(32px, 5vw, 48px)',
      fontWeight: 700,
      marginBottom: '48px',
    },
    widget: {
      display: 'flex',
      justifyContent: 'center',
    },
  };

  return (
    <section style={styles.section}>
      <div style={styles.container}>
        <p style={styles.tagline}>Отзиви</p>
        <h2 style={styles.title}>Какво казват клиентите</h2>
        <div style={styles.widget}>
          <div 
            className="fb-page" 
            data-href="https://www.facebook.com/p/Адвокат-Имилиана-Цонева-100057331124747/"
            data-tabs="reviews"
            data-width="500"
            data-height="600"
            data-small-header="true"
            data-adapt-container-width="true"
            data-hide-cover="false"
            data-show-facepile="false"
          >
          </div>
        </div>
      </div>
    </section>
  );
};

export default FacebookReviews;
